function solve(grid) {
    const m = grid.length;
    const n = grid[0].length;

    // The total number of steps in any path from (0, 0) to (m-1, n-1) is (m-1) + (n-1).
    // The total length of any path is (m-1) + (n-1) + 1 = m + n - 1.
    // The path always consists of exactly (m + n - 2) moves (right or down).

    // The problem constraints are m * n <= 1000. This suggests that a dynamic programming approach 
    // might be feasible if the state space is manageable.

    // Since the XOR operation is involved, standard DP (like finding the minimum sum) doesn't directly apply.
    // We need to find the minimum XOR sum among all paths.

    // The key insight, given the small constraint m*n <= 1000, is that the path length is at most 2000, 
    // but the number of paths can be very large (C(m+n-2, m-1)).

    // Since the maximum value of grid[i][j] is 1023, the maximum possible XOR sum is less than 1024 (i.e., 10 bits).
    // This suggests we can use a state representation that tracks the achievable XOR sums.

    // Let dp[i][j] be the set of all possible XOR sums achievable when reaching cell (i, j).

    // Initialize DP table: dp[i][j] will be a Set of numbers.
    const dp = Array(m).fill(0).map(() => Array(n).fill(0).map(() => new Set()));

    // Base case: Start cell (0, 0)
    dp[0][0].add(grid[0][0]);

    // Fill the first row
    for (let j = 1; j < n; j++) {
        const currentVal = grid[0][j];
        for (const prevXor of dp[0][j - 1]) {
            dp[0][j].add(prevXor ^ currentVal);
        }
    }

    // Fill the first column
    for (let i = 1; i < m; i++) {
        const currentVal = grid[i][0];
        for (const prevXor of dp[i - 1][0]) {
            dp[i][0].add(prevXor ^ currentVal);
        }
    }

    // Fill the rest of the table
    for (let i = 1; i < m; i++) {
        for (let j = 1; j < n; j++) {
            const currentVal = grid[i][j];

            // From above (i-1, j)
            for (const prevXor of dp[i - 1][j]) {
                dp[i][j].add(prevXor ^ currentVal);
            }

            // From left (i, j-1)
            for (const prevXor of dp[i][j - 1]) {
                dp[i][j].add(prevXor ^ currentVal);
            }
        }
    }

    // The result is the minimum value in the set dp[m-1][n-1]
    const finalXors = dp[m - 1][n - 1];

    if (finalXors.size === 0) {
        // Should not happen given constraints m>=1, n>=1
        return -1; 
    }

    let minXor = Infinity;
    for (const xor of finalXors) {
        if (xor < minXor) {
            minXor = xor;
        }
    }

    return minXor;
}

